import { useState, useEffect } from 'react';
import ProductList from './components/ProductList';
import ProductModal from './components/ProductModal';
import { getProducts } from './api/api';
import './styles/main.scss';

function App() {
  const [products, setProducts] = useState([]);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [error, setError] = useState(null);

  const loadProducts = async () => {
    try {
      const data = await getProducts();
      setProducts(data);
      setError(null);
    } catch (err) {
      console.error(err);
      setError('Не удалось загрузить меню. Проверьте сервер.');
    }
  };

  useEffect(() => {
    loadProducts();
  }, []);

  const handleOpenModal = (product = null) => {
    setEditingProduct(product);
    setModalOpen(true);
  };

  const handleCloseModal = () => {
    setModalOpen(false);
    setEditingProduct(null);
  };

  const handleSave = () => {
    loadProducts();
    handleCloseModal();
  };

  const handleDelete = async (id) => {
  try {
    console.log(`[App] Запускаю удаление id=${id}`);
    await deleteProduct(id);
    console.log(`[App] Удаление прошло успешно`);
    loadProducts(); // обновляем список
  } catch (err) {
    console.error('[App] Ошибка при удалении:', err);
    alert(`Не удалось удалить товар\n${err.message}`);
  }
};

// в рендере:
<ProductList
  products={products}
  onEdit={handleOpenModal}
  onDelete={handleDelete}
/>
  return (
    <div className="app-container">
      <header className="header">
        <h1>☕ Кофейня Bean & Brew</h1>
      </header>

      {error && <div className="error-message">{error}</div>}

      <button className="btn primary" onClick={() => handleOpenModal()}>
        + Добавить позицию в меню
      </button>

      <ProductList
        products={products}
        onEdit={handleOpenModal}
        onDelete={async (id) => {
          try {
            await deleteProduct(id);
            loadProducts();
          } catch (err) {
            alert('Не удалось удалить позицию');
          }
        }}
      />

      <ProductModal
        open={modalOpen}
        product={editingProduct}
        onClose={handleCloseModal}
        onSave={handleSave}
      />
    </div>
  );
}

export default App;
